import type { OTLPTraceExporter } from '@opentelemetry/exporter-trace-otlp-grpc';
import type { NodeTracerProvider } from '@opentelemetry/sdk-trace-node';
import type { DiagLogger } from '@opentelemetry/api';
import type { Activator } from './activator/types';
import type { O11YDefaults } from './config/config';
/**
 * Represents the TracingConfigs.
 */
export interface TracingConfigs {
    /**
     * Represents the default trace exporter.
     */
    defaultTraceExporter: OTLPTraceExporter;
    /**
     * Represents the events trace exporter.
     */
    tracerProvider: NodeTracerProvider;
}
/**
 * Represents the O11YEventsTracing configs.
 */
export interface O11YEventsTracing {
    activator: Activator;
    settings: O11YDefaults;
    logger: DiagLogger;
}
